def set_budget(budgets, category, amount):
    """Set the budget for a category (exact-match key) and return it."""
    budgets[category] = float(amount)
    return budgets[category]


def over_budget(records, budgets):
    """Return ``{category: budget}`` for categories whose summed duration
    exceeds their budget.

    A category exactly at its budget is not over. Budgets for categories
    with no records are ignored.
    """
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["duration"]
    return {
        category: budgets[category]
        for category in totals
        if category in budgets and totals[category] > budgets[category]
    }


